body:
/kind bug

**Description**

How to disable overwrite rules to nftables in rootful mode? Or how use force rootless mode?

**Steps to reproduce the issue:**

1. `cat /etc/cni/net.d/87-podman-bridge.conflist`
```
{
  "cniVersion": "0.4.0",
  "name": "podman",
  "plugins": [
    {
      "type": "bridge",
      "bridge": "cni-podman0",
      "isGateway": true,
      "ipMasq": true,
      "ipam": {
        "type": "host-local",
        "routes": [{ "dst": "0.0.0.0/0" }],
        "ranges": [
          [
            {
              "subnet": "10.88.0.0/16",
              "gateway": "10.88.0.1"
            }
          ]
        ]
      }
    },
    {
      "type": "portmap",
      "capabilities": {
        "portMappings": true
      }
    },
    {
      "type": "tuning"
    }
  ]
}
```

2. `systemctl restart nftables.service`

3. `nft list ruleset`
```
table inet filter {
    chain home {
        tcp dport ssh accept
    }

    chain input {
        type filter hook input priority 0; policy drop;
        ip protocol icmp icmp type echo-request accept
        iifname "lo" accept
        ct state { established, related } accept
        ip saddr 10.0.0.0/24 goto home
    }

    chain forward {
        type filter hook forward priority 0; policy accept;
    }

    chain output {
        type filter hook output priority 0; policy accept;
    }
}
```
4. `podman run --rm -d -p 8082:80 nginxdemos/hello`
5. `nft list ruleset` 
```
table inet filter {
    chain home {
        tcp dport ssh accept
    }

    chain input {
        type filter hook input priority 0; policy drop;
        ip protocol icmp icmp type echo-request accept
        iifname "lo" accept
        ct state { established, related } accept
        ip saddr 10.0.0.0/24 goto home
    }

    chain forward {
        type filter hook forward priority 0; policy accept;
    }

    chain output {
        type filter hook output priority 0; policy accept;
    }
}
table ip nat {
    chain PREROUTING {
        type nat hook prerouting priority -100; policy accept;
        fib daddr type local counter packets 0 bytes 0 jump CNI-HOSTPORT-DNAT
    }

    chain INPUT {
        type nat hook input priority 100; policy accept;
    }

    chain POSTROUTING {
        type nat hook postrouting priority 100; policy accept;
         counter packets 1 bytes 49 jump CNI-HOSTPORT-MASQ
        ip saddr 10.88.0.40  counter packets 0 bytes 0 jump CNI-32e01fe02b7a0a3daf937919
    }

    chain OUTPUT {
        type nat hook output priority -100; policy accept;
        fib daddr type local counter packets 0 bytes 0 jump CNI-HOSTPORT-DNAT
    }

    chain CNI-32e01fe02b7a0a3daf937919 {
        ip daddr 10.88.0.0/16  counter packets 0 bytes 0 accept
        ip daddr != 224.0.0.0/4  counter packets 0 bytes 0 masquerade
    }

    chain CNI-HOSTPORT-SETMARK {
         counter packets 0 bytes 0 meta mark set mark or 0x2000
    }

    chain CNI-HOSTPORT-MASQ {
        mark and 0x2000 == 0x2000 counter packets 0 bytes 0 masquerade
    }

    chain CNI-HOSTPORT-DNAT {
        meta l4proto tcp  tcp dport 8082 counter packets 0 bytes 0 jump CNI-DN-32e01fe02b7a0a3daf937
    }

    chain CNI-DN-32e01fe02b7a0a3daf937 {
        meta l4proto tcp ip saddr 10.88.0.40 tcp dport 8082 counter packets 0 bytes 0 jump CNI-HOSTPORT-SETMARK
        meta l4proto tcp ip saddr 127.0.0.1 tcp dport 8082 counter packets 0 bytes 0 jump CNI-HOSTPORT-SETMARK
        meta l4proto tcp tcp dport 8082 counter packets 0 bytes 0 dnat to 10.88.0.40:80
    }
}
table ip6 nat {
    chain PREROUTING {
        type nat hook prerouting priority -100; policy accept;
    }

    chain INPUT {
        type nat hook input priority 100; policy accept;
    }

    chain POSTROUTING {
        type nat hook postrouting priority 100; policy accept;
    }

    chain OUTPUT {
        type nat hook output priority -100; policy accept;
    }
}
```

